#include <IRremote.h>

const int IR_PIN = 11;
IRrecv irrecv(IR_PIN);
decode_results results;

void setup() {
  Serial.begin(9600);
  irrecv.enableIRIn(); // Start the receiver
  Serial.println("IR Receiver ready");
}

void loop() {
  if (irrecv.decode(&results)) {
    Serial.print("IR Code: 0x");
    Serial.println(results.value, HEX);

    // Take action based on button
    switch(results.value) {
      case 0xFF30CF: // Example: Button 1
        Serial.println("Button 1 pressed");
        break;
      case 0xFF18E7: // Example: Button 2
        Serial.println("Button 2 pressed");
        break;
      default:
        Serial.println("Unknown button");
    }

    irrecv.resume(); // Receive next value
  }
}

// Sound Sensor - Clap Switch Example
const int soundAnalog = A0;
const int soundDigital = 7;
const int ledPin = 13;
boolean ledState = false;

void setup() {
  pinMode(soundDigital, INPUT);
  pinMode(ledPin, OUTPUT);
  Serial.begin(9600);
  Serial.println("Sound Sensor Ready - Clap to toggle LED");
}

void loop() {
  // Read analog sound level
  int soundLevel = analogRead(soundAnalog);
  Serial.print("Sound Level: ");
  Serial.println(soundLevel);

  // Check digital trigger
  if (digitalRead(soundDigital) == LOW) {
    ledState = !ledState;
    digitalWrite(ledPin, ledState);
    Serial.println(ledState ? "LED ON" : "LED OFF");
    delay(500); // Debounce
  }

  delay(100);
}

