// TCS3200 Color Sensor
#define S0 4
#define S1 5
#define S2 6
#define S3 7
#define sensorOut 8

int redFreq = 0;
int greenFreq = 0;
int blueFreq = 0;

void setup() {
  Serial.begin(9600);
  pinMode(S0, OUTPUT);
  pinMode(S1, OUTPUT);
  pinMode(S2, OUTPUT);
  pinMode(S3, OUTPUT);
  pinMode(sensorOut, INPUT);

  // Set frequency scaling to 20%
  digitalWrite(S0, HIGH);
  digitalWrite(S1, LOW);
}

void loop() {
  // Read Red
  digitalWrite(S2, LOW);
  digitalWrite(S3, LOW);
  redFreq = pulseIn(sensorOut, LOW);

  // Read Green
  digitalWrite(S2, HIGH);
  digitalWrite(S3, HIGH);
  greenFreq = pulseIn(sensorOut, LOW);

  // Read Blue
  digitalWrite(S2, LOW);
  digitalWrite(S3, HIGH);
  blueFreq = pulseIn(sensorOut, LOW);

  Serial.print("R=");
  Serial.print(redFreq);
  Serial.print(" G=");
  Serial.print(greenFreq);
  Serial.print(" B=");
  Serial.println(blueFreq);

  // Identify dominant color
  if (redFreq < greenFreq && redFreq < blueFreq) {
    Serial.println("RED detected");
  } else if (greenFreq < redFreq && greenFreq < blueFreq) {
    Serial.println("GREEN detected");
  } else if (blueFreq < redFreq && blueFreq < greenFreq) {
    Serial.println("BLUE detected");
  }

  delay(1000);
}

// ACS712 Current Sensor (5A model)
const int sensorPin = A0;
const float sensitivity = 0.185; // 185mV/A for 5A model
const float vRef = 5.0;
const int zeroCurrentVoltage = 512; // 2.5V = 512 ADC value

void setup() {
  Serial.begin(9600);
  Serial.println("ACS712 Current Sensor");
}

void loop() {
  // Read sensor
  int sensorValue = analogRead(sensorPin);

  // Convert to voltage
  float voltage = (sensorValue / 1024.0) * vRef;

  // Calculate current
  float current = (voltage - 2.5) / sensitivity;

  Serial.print("Voltage: ");
  Serial.print(voltage, 3);
  Serial.print("V | Current: ");
  Serial.print(current, 3);
  Serial.println("A");

  // Check for over-current
  if (abs(current) > 4.5) {
    Serial.println("WARNING: Over-current detected!");
  }

  delay(500);
}

// SW-420 Vibration Sensor Alarm
