  pinMode(vibrationPin, INPUT);
  pinMode(alarmPin, OUTPUT);
  pinMode(ledPin, OUTPUT);

  Serial.begin(9600);
  Serial.println("Vibration Alarm System Active");

  // Attach interrupt
  attachInterrupt(digitalPinToInterrupt(vibrationPin), vibrationISR, RISING);
