  int p = finger.getImage();

  if (p != FINGERPRINT_OK) {
    delay(50);
    return;
  }

  p = finger.image2Tz();
  if (p != FINGERPRINT_OK) return;

  p = finger.fingerFastSearch();
  if (p == FINGERPRINT_OK) {
    Serial.print("Found ID #");
    Serial.print(finger.fingerID);
    Serial.print(" with confidence ");
    Serial.println(finger.confidence);
    Serial.println("ACCESS GRANTED!");
  } else {
    Serial.println("ACCESS DENIED!");
  }

  delay(1000);
}

// Requires HX711 library
#include <HX711.h>

#define DOUT_PIN 3
#define SCK_PIN 2

HX711 scale;

// Calibration factor (adjust after calibration)
float calibration_factor = -7050;

void setup() {
  Serial.begin(9600);
  Serial.println("HX711 Digital Scale");

  scale.begin(DOUT_PIN, SCK_PIN);

  Serial.println("Calibrating...");
  scale.set_scale(calibration_factor);
  scale.tare(); // Reset scale to 0

  Serial.println("Place known weight for calibration");
}

void loop() {
  Serial.print("Weight: ");
  Serial.print(scale.get_units(10), 2); // Average of 10 readings
  Serial.println(" grams");

  // Tare when 't' is pressed
  if (Serial.available()) {
    char command = Serial.read();
    if (command == 't' || command == 'T') {
      scale.tare();
      Serial.println("Scale tared");
    }
  }

  delay(500);
}

/* Calibration Process:
1. Place empty container and tare
2. Place known weight (e.g., 100g)
3. Adjust calibration_factor until reading is correct
4. Save calibration_factor for future use
*/

// KY-026 Flame Sensor Module
const int flameAnalog = A1;
const int flameDigital = 5;
const int alarmPin = 9;
const int ledPin = 13;

int threshold = 600; // Analog threshold

void setup() {
  pinMode(flameDigital, INPUT);
  pinMode(alarmPin, OUTPUT);
  pinMode(ledPin, OUTPUT);
  Serial.begin(9600);
  Serial.println("KY-026 Flame Detection System");
}

void loop() {
  int analogValue = analogRead(flameAnalog);
  int digitalValue = digitalRead(flameDigital);

  Serial.print("Analog: ");
  Serial.print(analogValue);
  Serial.print(" | Digital: ");
  Serial.print(digitalValue);

  // Flame detection logic
  if (digitalValue == LOW || analogValue > threshold) {
    Serial.println(" - FLAME DETECTED!");
    digitalWrite(ledPin, HIGH);

    // Sound alarm
    tone(alarmPin, 1000, 200);
    delay(300);
    tone(alarmPin, 1500, 200);
    delay(300);
  } else {
    Serial.println(" - Normal");
    digitalWrite(ledPin, LOW);
    noTone(alarmPin);
  }

  delay(500);
}
